```

```cpp
// In setCalibrationActive:
void setCalibrationActive(bool active) {
if (!active) {
// Only suppress smoothing if the user didn't explicitly enable it
if (!m_userEnabledSmoothing) {
applySmoothingState(false);
}
// else: leave smoothing alone, user owns the state
} else {
// Calibration starting — suspend smoothing regardless
applySmoothingState(false);
}
}
```

